for (const item of $input.all()) {
  let rawText = item.json.text || "";

  try {
    // Bersihkan karakter newline atau spasi aneh jika ada
    const cleanText = rawText.trim();
    const data = JSON.parse(cleanText);

    // Validasi & fallback jika jam_mulai atau jam_selesai bernilai null
    const jamMulaiClean = data.jam_mulai || "00:00"; 
    const tanggalAcara = data.tanggal_acara || "1970-01-01";

    // 1. Buat format Start Time standar ISO (YYYY-MM-DDTHH:mm:ss)
    const startDateTime = `${tanggalAcara}T${jamMulaiClean}:00`;

    // 2. Buat logika End Time dan simpan jam selesai bersih
    let endDateTime;
    let jamSelesaiClean;

    if (data.jam_selesai) {
      endDateTime = `${tanggalAcara}T${data.jam_selesai}:00`;
      jamSelesaiClean = data.jam_selesai;
    } else {
      // Jika jam_selesai null, tambahkan 1 jam dari jamMulaiClean
      const [hours, minutes] = jamMulaiClean.split(':').map(Number);
      let endHours = hours + 1;

      // Antisipasi jika penambahan 1 jam melewati tengah malam (24:00 -> 00:00)
      if (endHours >= 24) {
        endHours = endHours % 24;
      }

      const endHoursStr = String(endHours).padStart(2, '0');
      const endMinutesStr = String(minutes).padStart(2, '0');

      endDateTime = `${tanggalAcara}T${endHoursStr}:${endMinutesStr}:00`;
      jamSelesaiClean = `${endHoursStr}:${endMinutesStr}`;
    }

    // 3. Dapatkan Tanggal Sekarang (Format YYYY-MM-DD di zona waktu WIB)
    const sekarang = new Date();
    const wibOffset = 7 * 60 * 60 * 1000;
    const waktuWIB = new Date(sekarang.getTime() + (sekarang.getTimezoneOffset() * 60000) + wibOffset);
    const tanggalSekarang = waktuWIB.toISOString().split('T')[0];

    // 4. Keluarkan output yang sudah bersih siap pakai
    item.json = {
      title: data.nama_acara || "Acara Tanpa Nama",
      tanggal_acara: String(tanggalAcara),
      start_time: startDateTime,
      end_time: endDateTime,
      jam_mulai: jamMulaiClean,
      jam_selesai: jamSelesaiClean,
      tanggal_sekarang: tanggalSekarang,
      description: data[" Raw Text"] || data["Raw Text"] || "",
      process: "Finish",
      intent: data.predicted_intent || "JADWAL"
    };
