for (const item of $input.all()) {
  let rawText = item.json.text || item.json.output || "";

  // 1. Ubah \n literal menjadi enter nyata
  rawText = rawText.replace(/\\n/g, '\n');

  let lines = rawText.split('\n');
  let formattedLines = [];
  let isInsideTable = false;
  let tableHeaders = [];

  for (let line of lines) {
    let trimmed = line.trim();

    // Abaikan baris pembatas tabel Markdown (---|---|---)
    if (trimmed.includes('---|') || trimmed.includes('---')) {
      if (trimmed.startsWith('|') && trimmed.endsWith('|')) continue;
    }

    // PROSES JIKA BARIS ADALAH TABEL
    if (trimmed.startsWith('|') && trimmed.endsWith('|')) {
      let cells = trimmed.split('|').map(c => c.trim()).filter(c => c !== '');

      if (!isInsideTable) {
        // Baris Header Tabel
        tableHeaders = cells.map(c => c.replace(/\*\*/g, ''));
        isInsideTable = true;
        formattedLines.push('\n📊 *DETAIL DATA*\n───────────────────');
      } else {
        // Baris Isi Tabel
        let rowBox = [];
        cells.forEach((cell, index) => {
          let headerName = tableHeaders[index] || `Kolom ${index + 1}`;
          let cleanCell = cell.replace(/\*\*/g, ''); // Fix: Karakter '转' sudah dihapus
          rowBox.push(`🔹 *${headerName}:* ${cleanCell}`);
        });
        formattedLines.push(rowBox.join('\n') + '\n───────────────────');
      }
    } else {
      // PROSES JIKA BARIS BUKAN TABEL
      if (isInsideTable) isInsideTable = false;

      if (trimmed.startsWith('##')) {
        // Judul/Sub-bab: Menggunakan format *TEKS TEBAL KAPITAL*
        let headingText = trimmed.replace(/^##+\s+/, '').toUpperCase();
        formattedLines.push(`\n📌 *${headingText}*\n━━━━━━━━━━━━━━━━━━━`);
      } else if (trimmed !== '') {
        // Teks biasa: Standarisasi format **bold** LLM menjadi *bold* Telegram
        let formattedLine = trimmed.replace(/\*\*(.*?)\*\*/g, '*$1*');
        formattedLines.push(formattedLine);
      } else {
        // Pertahankan baris kosong untuk spasi antar paragraf
        formattedLines.push('');
      }
    }
  }

  // Gabungkan semua menjadi satu string teks bersih
  item.json.telegram_text = formattedLines.join('\n').trim();

  // Menyimpan status ke dalam JSON secara aman
  item.json.process_status = "Finish"; 
}

// Return array item n8n yang valid
